setPane('level-withdrawal-no-option', createDualContent(
  "No Withdrawal Option Available\n\n" +
  "Troubleshooting Steps\n\n" +
  "1. Verify whether the user meets the eligibility requirements.\n" +
  "   \u2022 If not, guide the user accordingly and encourage further app engagement.\n\n" +
  "2. Check Dashboard \u2192 User Details.\n" +
  "   \u2022 If Verified Diamonds_new Balance > -15,000, advise the user to wait until recently received diamonds are reviewed and refunded if applicable.\n\n" +
  "3. If the issue persists after all checks:\n" +
  "   \u2022 Escalate to the SUGO QA-CS Team Group.\n" +
  "   \u2022 Tag @Violet to verify whether the user is on the withdrawal blacklist or has any outstanding debts.",

  "\u0644\u0627 \u064a\u0648\u062c\u062f \u062e\u064a\u0627\u0631 \u0633\u062d\u0628 \u0645\u062a\u0627\u062d\n\n" +
  "\u062e\u0637\u0648\u0627\u062a \u0627\u0633\u062a\u0643\u0634\u0627\u0641 \u0627\u0644\u0623\u062e\u0637\u0627\u0621 \u0648\u0625\u0635\u0644\u0627\u062d\u0647\u0627\n\n" +
  "1. \u062a\u062d\u0642\u0642 \u0645\u0645\u0627 \u0625\u0630\u0627 \u0643\u0627\u0646 \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u064a\u0633\u062a\u0648\u0641\u064a \u0645\u062a\u0637\u0644\u0628\u0627\u062a \u0627\u0644\u0623\u0647\u0644\u064a\u0629.\n" +
  "   \u2022 \u0625\u0630\u0627 \u0644\u0645 \u064a\u0643\u0646 \u0643\u0630\u0644\u0643\u060c \u0648\u062c\u0651\u0647 \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0648\u0641\u0642\u0627\u064b \u0644\u0630\u0644\u0643 \u0648\u0634\u062c\u0651\u0639\u0647 \u0639\u0644\u0649 \u0627\u0633\u062a\u0643\u0634\u0627\u0641 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0623\u0643\u062b\u0631.\n\n" +
  "2. \u062a\u062d\u0642\u0642 \u0645\u0646 \u0644\u0648\u062d\u0629 \u0627\u0644\u0645\u0639\u0644\u0648\u0645\u0627\u062a \u2190 \u062a\u0641\u0627\u0635\u064a\u0644 \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645.\n" +
  "   \u2022 \u0625\u0630\u0627 \u0643\u0627\u0646 \u0631\u0635\u064a\u062f Verified Diamonds_new Balance > -15,000\u060c \u0627\u0646\u0635\u062d \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0628\u0627\u0644\u0627\u0646\u062a\u0638\u0627\u0631 \u062d\u062a\u0649 \u062a\u062a\u0645 \u0645\u0631\u0627\u062c\u0639\u0629 \u0627\u0644\u0645\u0627\u0633\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u0644\u0645\u0629 \u0645\u0624\u062e\u0631\u0627\u064b.\n\n" +
  "3. \u0625\u0630\u0627 \u0627\u0633\u062a\u0645\u0631\u062a \u0627\u0644\u0645\u0634\u0643\u0644\u0629 \u0628\u0639\u062f \u062c\u0645\u064a\u0639 \u0627\u0644\u0641\u062d\u0648\u0635\u0627\u062a:\n" +
  "   \u2022 \u0635\u0639\u0651\u062f \u0625\u0644\u0649 \u0645\u062c\u0645\u0648\u0639\u0629 SUGO QA-CS Team.\n" +
  "   \u2022 \u0648\u0633\u0651\u0645 @Violet \u0644\u0644\u062a\u062d\u0642\u0642 \u0645\u0645\u0627 \u0625\u0630\u0627 \u0643\u0627\u0646 \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0641\u064a \u0627\u0644\u0642\u0627\u0626\u0645\u0629 \u0627\u0644\u0633\u0648\u062f\u0627\u0621 \u0644\u0644\u0633\u062d\u0628 \u0623\u0648 \u0644\u062f\u064a\u0647 \u062f\u064a\u0648\u0646 \u0645\u0633\u062a\u062d\u0642\u0629."
));

